INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Feedback Boards$q$, $q$Public or private boards where users and teammates submit and upvote feature requests.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Autopilot AI$q$, $q$Built-in AI that deduplicates feedback, summarizes threads, and drafts replies, included on every plan including Free.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Roadmaps$q$, $q$Visual, shareable roadmaps showing what's planned, in progress, and shipped.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Changelog$q$, $q$A built-in changelog widget to announce shipped features back to the customers who requested them.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Feedback Capture Integrations$q$, $q$Pulls in requests from Intercom, Zendesk, Slack, and a Chrome extension.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Project Management Integrations$q$, $q$Pushes prioritized items to Jira, Linear, ClickUp, Asana, GitHub, and Azure DevOps.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Segmentation & Admin Roles$q$, $q$Pro-tier controls for targeting feedback prompts to specific user segments and restricting admin permissions.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Generous free plan with core AI features included$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Bootstrapped, profitable company with a long operating track record$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Deep integrations with common support and engineering tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Simple, purpose-built interface compared to general-purpose project trackers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Business-tier pricing is not published and requires a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Tracked-user pricing can grow quickly for products with large user bases$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$No native support ticketing of its own — relies on integrations for that$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Portal customization is more limited on Free and Pro than on Business$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Is Canny free to use?$q$, $q$Yes. Canny has a permanent Free plan for up to 25 tracked users with unlimited posts, boards, and access to Autopilot AI; paid plans start at $79/month for higher usage tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Who founded Canny?$q$, $q$Canny was founded in 2015 by Sarah Hum and Andrew Rasmussen, who previously worked together as a designer and engineer at Meta.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$What is Canny's Autopilot AI?$q$, $q$Autopilot is Canny's built-in AI layer that deduplicates similar feedback, summarizes comment threads, and drafts replies. It's available on every plan, including Free.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Does Canny integrate with Jira and Linear?$q$, $q$Yes. The Pro and Business plans include native integrations with Jira, Linear, ClickUp, Asana, GitHub, and Azure DevOps for pushing prioritized feedback into engineering workflows.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Can I use a custom domain for my Canny feedback portal?$q$, $q$Yes, custom domains are available starting on paid plans, letting companies host their feedback board and changelog under their own domain.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Public Product Roadmaps$q$, $q$SaaS companies publish a transparent roadmap to build customer trust and reduce 'when is X shipping' support questions.$q$, $q$B2B SaaS product teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Internal Feedback Triage$q$, $q$Product managers consolidate requests from support tickets, sales calls, and in-app prompts into one prioritized backlog.$q$, $q$Product managers and founders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Customer-Facing Changelogs$q$, $q$Teams announce shipped features back to the specific customers who requested them, closing the feedback loop.$q$, $q$Product marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Up to 25 tracked users","5 manager seats","Unlimited posts and boards","Autopilot AI included"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Pro$q$, $q$$79/month$q$, $q$Billed yearly (monthly billing available)$q$, NULL, $q$["100+ tracked users","10 manager seats","Custom domains","PM tool integrations (Jira, Linear, ClickUp, Asana)","Automation rules and segmentation"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$Business$q$, $q$Custom$q$, $q$Contact sales$q$, NULL, $q$["5,000+ tracked users","SSO integrations","CRM integrations","Enterprise-scale support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Canny is feedback management software that gives product teams a single, structured place to collect user requests, decide what to build, and tell customers when it ships. It replaces the common pattern of feedback scattered across support tickets, spreadsheets, and sales notes with public or private voting boards, a visual roadmap, and a built-in changelog.$q$, $q$The company was founded in 2015 by Sarah Hum and Andrew Rasmussen, who met working as a designer and engineer at Meta, and is headquartered in San Francisco. Canny has grown as a bootstrapped, profitable company rather than a venture-backed one, which it frequently cites as evidence of long-term product stability.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Feedback is captured through customizable boards where users and teammates submit and upvote ideas, and can also flow in automatically from Intercom, Zendesk, Slack, and a Chrome extension so support teams can log requests without switching tools.$q$, $q$Canny's AI layer, Autopilot, is bundled into every plan, including Free. It deduplicates similar submissions, summarizes long comment threads, and drafts suggested replies, reducing the manual triage work of running a feedback inbox.$q$, $q$Prioritized feedback can be pushed directly into engineering workflows through native integrations with Jira, Linear, ClickUp, Asana, GitHub, and Azure DevOps, keeping the roadmap and the backlog in sync without manual re-entry.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de66f380-8299-4b3a-b413-b14569d70119', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Canny uses a freemium, tracked-user-based pricing model with three published tiers. Free covers up to 25 tracked users with unlimited posts, boards, and Autopilot AI. Pro, at $79/month billed yearly, adds custom domains, translations, PM tool integrations, segmentation, and automation rules for larger or more structured teams.$q$, $q$The top-tier Business plan is not publicly priced and requires a sales conversation; it adds SSO, CRM integrations, and support for very high tracked-user volumes. Canny offers a roughly 20% discount for annual billing and has separate reduced pricing for qualified non-profits.$q$]::text[], 2);
