INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7e8227b7-0e90-46d7-92df-86b14a774f8a', $q$Cross-platform apps for web, iOS, Android, Mac, and Windows$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7e8227b7-0e90-46d7-92df-86b14a774f8a', $q$Free Pro-equivalent access for verified teachers, students, and nonprofits$q$, 3);
