INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7e8227b7-0e90-46d7-92df-86b14a774f8a', $q$Most features require an internet connection, limiting offline design work$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e8227b7-0e90-46d7-92df-86b14a774f8a', $q$Is Canva free?$q$, $q$Yes, Canva's Free plan is permanently free and includes 250,000+ templates, 5GB of storage, and the core editor.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e8227b7-0e90-46d7-92df-86b14a774f8a', $q$What does Canva Pro include?$q$, $q$Canva Pro ($15/month or $120/year) adds 1TB of storage, premium templates and stock content, a background remover, and the Magic Studio AI tools.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e8227b7-0e90-46d7-92df-86b14a774f8a', $q$What is Magic Studio?$q$, $q$Magic Studio is Canva's suite of generative AI design tools, including Magic Write, Magic Design, Magic Eraser, and Magic Expand.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e8227b7-0e90-46d7-92df-86b14a774f8a', $q$Is Canva free for teachers and students?$q$, $q$Yes, Canva for Education provides the Pro feature set at no cost to verified K-12 teachers and students.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e8227b7-0e90-46d7-92df-86b14a774f8a', $q$What's the difference between Canva Pro and Business?$q$, $q$Pro is priced per individual user, while Business ($20/user/month) adds team features like shared Brand Kits, approval workflows, and multi-user administration.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e8227b7-0e90-46d7-92df-86b14a774f8a', $q$Does Canva have an API for developers?$q$, $q$Yes, the Canva Connect API and Canva Apps SDK let developers build integrations and apps that appear in Canva's apps marketplace.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7e8227b7-0e90-46d7-92df-86b14a774f8a', $q$Social Media & Marketing Content$q$, $q$Small business owners and marketers produce on-brand social posts and ads without hiring a designer.$q$, $q$Marketers and small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7e8227b7-0e90-46d7-92df-86b14a774f8a', $q$Team Brand Management$q$, $q$Mid-sized companies use Brand Kits and approval workflows to standardize visual assets across many contributors.$q$, $q$Marketing and operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7e8227b7-0e90-46d7-92df-86b14a774f8a', $q$Classroom & Student Projects$q$, $q$Teachers and students create presentations, worksheets, and assignments using free Canva for Education access.$q$, $q$Educators and students$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7e8227b7-0e90-46d7-92df-86b14a774f8a', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["250,000+ templates","5GB storage","Basic editor","Stock photos and graphics"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7e8227b7-0e90-46d7-92df-86b14a774f8a', $q$Pro$q$, $q$$15/month or $120/year$q$, $q$Monthly or annual$q$, NULL, $q$["1TB storage","Magic Studio AI tools","Premium templates and stock content","Background remover","Unlimited Brand Kits"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7e8227b7-0e90-46d7-92df-86b14a774f8a', $q$Business$q$, $q$$20/user/month or $200/user/year$q$, $q$Monthly or annual$q$, NULL, $q$["Brand Kit and approval workflows","Shared team libraries","Multi-user administration"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7e8227b7-0e90-46d7-92df-86b14a774f8a', $q$Enterprise$q$, $q$Custom (150+ seat minimum)$q$, $q$Annual contract$q$, NULL, $q$["Single sign-on (SSO)","SCIM provisioning","Audit logs","Dedicated customer success manager"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7e8227b7-0e90-46d7-92df-86b14a774f8a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Canva was founded in 2013 by Melanie Perkins, Cliff Obrecht, and Cameron Adams, after Perkins spent years teaching students how to use traditional desktop design software and grew frustrated with its complexity. The company is headquartered in Sydney, Australia, employs over 4,000 people, and has become one of the most widely used design tools in the world, used by individuals, marketing teams, educators, and nonprofits.$q$, $q$Canva's editor runs in a browser and as native apps for iOS, Android, Mac, and Windows. It is built around a large template library covering social media graphics, presentations, documents, videos, print materials, and websites, with a Free plan that includes more than 250,000 templates and 5GB of storage at no cost.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7e8227b7-0e90-46d7-92df-86b14a774f8a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Magic Studio is Canva's suite of generative AI tools, including Magic Write for text generation, Magic Design for automated layout suggestions, Magic Eraser and Magic Expand for photo editing, and AI-assisted video tools. These are unlocked starting on the Pro plan.$q$, $q$For teams, Canva Business adds Brand Kits, approval workflows, and shared team libraries to keep visual output consistent across many contributors. Canva has also expanded beyond design into an adjacent productivity suite — Canva Docs, Whiteboards, Presentations, and Sheets — plus a print-and-merchandise fulfillment service.$q$, $q$A developer platform (Canva Apps SDK and Canva Connect API) powers an apps marketplace with 300+ third-party integrations, including Slack, HubSpot, Dropbox, and Asana, letting teams connect Canva to their existing workflow tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7e8227b7-0e90-46d7-92df-86b14a774f8a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Canva uses a four-tier freemium model. Free includes the core editor and template library. Pro is $15/month or $120/year per user and adds premium content, 1TB storage, and Magic Studio AI tools. Business is $20/user/month or $200/user/year and adds brand and approval controls for teams; it has replaced the older flat-rate Canva Teams plan for new customers.$q$, $q$Enterprise is custom-quoted, generally requires around 150+ seats, and adds SSO, SCIM provisioning, audit logs, and a dedicated customer success manager. Canva also sells an AI Pass add-on (around $100/person/month) for Pro and Business users who need significantly higher AI usage limits. Canva for Education and Canva for Nonprofits provide the Pro feature set free to verified teachers, students, and registered nonprofits.$q$]::text[], 2);
