INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Canvas Studio$q$, $q$Video-based learning tools integrated into the course experience.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Canvas Commons$q$, $q$Shared content library for exchanging course materials between instructors and institutions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Open API & LTI Integrations$q$, $q$Well-documented REST API and LTI support connecting to 1,000+ third-party tools.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Deep, well-documented API and LTI ecosystem for integrations$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Free, self-hostable open-source version available under AGPLv3$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Strong grading and feedback tools (SpeedGrader) valued by instructors$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Widely adopted, so training resources and course content are broadly transferable between institutions$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Commercial hosted pricing is not published and requires a sales negotiation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Self-hosting the open-source version requires in-house technical infrastructure and maintenance$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Feature set and update cadence can differ between the hosted commercial product and the open-source release$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Can feel like more platform than necessary for very small training programs$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Is Canvas LMS free?$q$, $q$The source code is free and open-source under AGPLv3 for organizations that self-host it. The fully hosted, supported commercial version sold by Instructure requires a paid institutional contract.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Who owns Canvas LMS?$q$, $q$Canvas is built by Instructure, founded in 2008 by Brian Whitmer and Devlin Daley and headquartered in Salt Lake City, Utah.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$What is SpeedGrader?$q$, $q$SpeedGrader is Canvas's grading tool that shows a student's submission, rubric, and grade field on one screen, with PDF annotation and video feedback.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Does Canvas have a mobile app?$q$, $q$Yes, Instructure offers native iOS and Android apps for both students and teachers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Can Canvas integrate with other education tools?$q$, $q$Yes, via its open REST API and support for the LTI standard, connecting to more than 1,000 third-party educational tools.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Higher Education Course Delivery$q$, $q$Universities run large-scale online and blended courses with modules, quizzes, and grading tools.$q$, $q$Universities and colleges$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$K-12 Virtual Learning$q$, $q$School districts manage assignments, grading, and student/parent communication.$q$, $q$K-12 schools$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Self-Hosted Training Environments$q$, $q$Organizations with in-house IT run a free, customizable LMS without per-student licensing fees.$q$, $q$Technical teams and training providers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full Canvas codebase under AGPLv3 license","Self-host on your own infrastructure","Community support","No per-student licensing fee"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$Instructure-Hosted (Institutional)$q$, $q$Custom quote$q$, $q$Annual contract$q$, NULL, $q$["Fully hosted and maintained by Instructure","Institution-wide support and SLAs","Access to Canvas Studio and Commons","Pricing based on enrollment size"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Canvas is a learning management system built by Instructure, founded in 2008 by BYU graduate students Brian Whitmer and Devlin Daley and headquartered in Salt Lake City, Utah. Canvas launched in 2011 as a cloud-native alternative to older on-premise LMS platforms and is now used by more than 4,000 institutions and roughly 28 million students, teachers, and administrators globally.$q$, $q$Canvas is unusual among major LMS platforms in that it is dual-licensed: Instructure sells a fully hosted, supported commercial version to institutions, while the same core codebase is released as free, open-source software under the AGPLv3 license, so technically capable organizations can self-host it without paying a licensing fee.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform's core is course and content management — modules, assignments, quizzes, and discussion boards — paired with a customizable Gradebook and SpeedGrader, which lets instructors view a submission, rubric, and grade field on one screen, annotate PDFs, and leave text or video feedback.$q$, $q$Mastery Paths and Instructure's Outcomes and Mastery Connect tools support competency-based learning that branches based on assessment performance. Canvas Studio adds video-based learning, and Canvas Commons lets instructors and institutions share course content with one another.$q$, $q$Canvas has one of the more extensively documented APIs in the LMS category and supports the LTI interoperability standard, connecting to more than 1,000 third-party educational tools. Native mobile apps for students and teachers cover assignment submission, discussions, grading, and mobile SpeedGrader.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Institutional pricing for the Instructure-hosted commercial version is not publicly published and is negotiated per contract based on factors like enrollment size; prospective customers need to request a quote from Instructure's sales team.$q$, $q$Because the core Canvas codebase is open source under AGPLv3, organizations with their own technical infrastructure can self-host Canvas at no licensing cost, though they take on the work of installation, maintenance, and support themselves rather than relying on Instructure's managed hosting and support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2db842ea-f8cf-4398-9294-2de09ec16c62', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
