INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$Object-Based Notes$q$, $q$Content is organized as typed objects (Person, Book, Meeting, etc.) instead of freeform files.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$Properties & Relations$q$, $q$Each object type carries structured properties and can be linked to other objects.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$Graph View$q$, $q$Interactive visualization of how objects and notes connect to one another.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$Daily Notes$q$, $q$A dedicated space for quick daily capture of tasks, meetings, and ideas.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$AI Assistant$q$, $q$Paid-plan AI that answers questions about your own notes, summarizes content, and helps draft entries.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$Offline-First Sync & Export$q$, $q$Local-first storage with cross-device sync, plus export to Markdown, HTML, or JSON.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$Usable free tier with unlimited notes and objects$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$Structured object model gives more built-in organization than plain markdown notes$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$True cross-platform coverage including native mobile apps$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$No lock-in thanks to open export formats$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$Smaller plugin/integration ecosystem than more established tools like Notion or Obsidian$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$AI assistant is gated behind a paid plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$Learning the object-type model takes longer than starting a blank page in a simpler notes app$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$Small team size relative to larger competitors may affect roadmap pace$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$Is Capacities free?$q$, $q$Yes, the Free plan has no limit on notes or objects and includes 5GB of storage for media.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$What makes Capacities different from Notion?$q$, $q$Capacities organizes information as typed objects with structured properties and relations, rather than freeform pages, and renders those connections as an interactive graph.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$Does Capacities work offline?$q$, $q$Yes, it's offline-first — content is stored locally and syncs across devices once a connection is available.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$Is there a mobile app for Capacities?$q$, $q$Yes, native iOS and Android apps launched in July 2024, along with tablet-optimized versions for iPad and Android tablets.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$Can I export my data out of Capacities?$q$, $q$Yes, your knowledge base can be exported to Markdown, HTML, or JSON.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$Personal Knowledge Management$q$, $q$Researchers and writers organize notes, sources, and ideas as linked objects rather than a flat file tree.$q$, $q$Researchers, writers, and students$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$Daily Journaling & Task Capture$q$, $q$Professionals use Daily Notes to log meetings, tasks, and reflections in a structured way.$q$, $q$Knowledge workers$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Unlimited notes and objects","5GB media storage","Core object types and templates","Offline mode"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$Pro$q$, $q$$9.99/month (annual) or $11.99/month$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited storage","AI assistant","Saved queries","Calendar integration","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$Believer$q$, $q$$12.49/month (annual) or $14.99/month$q$, $q$Monthly or annual$q$, NULL, $q$["Same features as Pro","Supports ongoing product development"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Capacities is a note-taking and personal knowledge management app built by Capacities Labs GmbH, founded in 2020 by Steffen Bleher and Michael von Hohnhorst and based in Sankt Wendel, Germany. Rather than storing information as generic pages or files, Capacities organizes content around typed objects — a Person, a Book, a Meeting, a Daily Note — each with its own structured properties.$q$, $q$Objects can be linked together and explored through an interactive graph view, giving users a way to navigate a knowledge base by relationship instead of a folder tree, which the company positions as a middle ground between the flexibility of networked notes and the structure of a database.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include Daily Notes for quick capture, custom object types and templates, properties and relations for structuring data, and tagging and collections for grouping related objects. An AI assistant, available on paid plans, can answer questions about a user's own notes, summarize content, and help draft new entries.$q$, $q$The app is offline-first, syncing across devices once a connection is available, and supports export to Markdown, HTML, or JSON to avoid vendor lock-in. Capacities runs as native apps on Mac, Windows, and Linux, as a web app, and, since July 2024, as native iOS and Android apps with tablet-optimized versions.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Capacities offers a Free plan with no cap on notes or objects and 5GB of media storage, making it usable as a primary note app without paying. Pro costs $9.99/month billed annually ($11.99 monthly) and adds unlimited storage, the AI assistant, saved queries, and calendar integration.$q$, $q$A Believer plan, at $12.49/month annually ($14.99 monthly), includes the same features as Pro but is framed by the company as a way for users to directly support ongoing development.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
