INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
