INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5816d708-5e16-4d8f-8847-bc4d396ab602', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$Capchase Grow$q$, $q$Non-dilutive financing that advances a portion of a company's future ARR.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$Capchase Pay$q$, $q$B2B buy-now-pay-later style financing that lets buyers pay in installments while vendors get paid upfront.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$Automated Underwriting$q$, $q$Connects banking, accounting, and billing data to return financing offers within 24-48 hours.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$Non-Dilutive Capital$q$, $q$Financing that doesn't require giving up equity or board seats.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$Flexible Repayment Terms$q$, $q$Repayment terms generally ranging from 3 to 12 months, depending on the product and deal.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$Split Financing Fees$q$, $q$On Capchase Pay, the financing fee can be paid by the vendor, the buyer, or split between them.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$No equity dilution or board seats required, unlike venture capital$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$Fast underwriting turnaround, typically 24-48 hours, versus traditional bank loans$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$Flexible fee-sharing on Capchase Pay between vendor and buyer$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$Purpose-built for recurring-revenue software businesses rather than generic business loans$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$Pricing isn't public — companies must apply and go through underwriting to learn their actual cost of capital$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$Requires minimum ARR and runway thresholds, so it isn't accessible to pre-revenue or very early-stage startups$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$Flat discount fees on short-term financing can equate to a high effective annual rate compared with traditional debt$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$Requires connecting banking, accounting, and billing data for underwriting$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$What is Capchase Grow?$q$, $q$Capchase Grow is a revenue-based financing product that advances a portion of a SaaS company's future annual recurring revenue in exchange for a flat fee.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$What is Capchase Pay?$q$, $q$Capchase Pay is a B2B payment product that lets a vendor's customers pay for annual or multi-year contracts in installments, while the vendor is paid the full contract value upfront.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$Is Capchase financing dilutive?$q$, $q$No, Capchase's financing products are non-dilutive — companies don't give up equity or board seats.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$How fast can a company get funded through Capchase?$q$, $q$Underwriting decisions are typically returned within 24 to 48 hours after a company connects its banking, accounting, and billing data.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$Who is eligible for Capchase financing?$q$, $q$Primarily B2B SaaS and hardware companies with recurring revenue meeting Capchase's minimum ARR and cash runway requirements.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$Extending Cash Runway Between Funding Rounds$q$, $q$Growth-stage SaaS companies smooth out cash flow from annual contracts without raising a new equity round.$q$, $q$SaaS finance teams and founders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$Flexible Payment Terms for Customers$q$, $q$Software vendors offer buyers installment payments on annual contracts while still getting paid upfront themselves.$q$, $q$B2B sales and finance teams$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Capchase is a fintech company founded in 2020 and headquartered in New York, with additional offices in Madrid and Barcelona. It builds financing and payment products specifically for B2B software companies, and reports having funded more than 4,000 companies with over $2.5 billion in total financing.$q$, $q$The company's underwriting is automated: applicants connect their banking, accounting, and billing systems, and Capchase's algorithms assess the quality of their recurring revenue to return a financing offer, typically within 24 to 48 hours, without a pitch deck or business plan.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Capchase Grow is the core revenue-based financing product, advancing roughly 20 to 70 percent of a company's ARR against future recurring revenue, with transaction sizes from about $25,000 to $10 million and repayment terms generally spanning three to twelve months.$q$, $q$Capchase Pay addresses the buyer side of a deal: it lets a software vendor's customer pay for an annual or multi-year contract in installments while the vendor still collects the full contract value upfront, with the financing fee payable by the vendor, buyer, or split between them.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Capchase does not publish fixed pricing tiers. Capchase Grow charges a flat discount fee, commonly cited around 10 to 12 percent, split since 2023 into a Platform Fee (roughly 1 to 4 percent) and a separate Financing Fee, and generally requires a minimum ARR floor around $150,000.$q$, $q$Capchase Pay charges a flat financing fee per deal that can be paid by the vendor, the buyer, or split between them, with no separate platform, implementation, or integration fees. Exact terms for both products are determined per company through Capchase's underwriting process.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('53147b31-f2fc-40d8-abf5-b79accdf962a', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$One-Click App Deployment$q$, $q$Deploy apps via CLI, web dashboard, Git webhook, Dockerfile, or prebuilt image.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$Docker + Nginx Automation$q$, $q$Automates container orchestration and reverse-proxy configuration behind the scenes.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$Free Automatic SSL$q$, $q$Automatic Let's Encrypt certificate issuance and renewal for every app and domain.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$Docker Swarm Clustering$q$, $q$Built-in support for running apps across multiple nodes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$CLI and Web Dashboard$q$, $q$Command-line tooling for automation plus a browser-based management UI.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$Git Webhook Deploys$q$, $q$Auto-generated webhooks for pushing deployments straight from a Git repository.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$One-Click App Marketplace$q$, $q$Install common software like WordPress and popular databases with a single click.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$Completely free to run — the only cost is your own server$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$Automates SSL, reverse proxying, and container orchestration that would otherwise require manual setup$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$Works on virtually any Docker-capable machine, including low-cost VPS providers and Raspberry Pi$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$Large, active community with a track record dating back to 2017$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$Requires the user to provision, secure, and maintain their own server — there is no managed hosting option from the project itself$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$No official enterprise support contract or SLA in the way a managed PaaS vendor would offer$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$Licensing changed in 2023 to a modified Apache License that restricts redistribution of certain paid features$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$Less polished UI/UX than fully managed commercial PaaS competitors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$Is CapRover free?$q$, $q$Yes, the core CapRover platform is free to download and run; the only cost is the server you deploy it on.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$What is CapRover built on?$q$, $q$CapRover automates Docker, Nginx, and Let's Encrypt, with optional Docker Swarm clustering for multi-node setups.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$Who created CapRover?$q$, $q$Kasra Bigdeli created CapRover, originally releasing it as CaptainDuckDuck in October 2017.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$Is CapRover open source?$q$, $q$Its source is publicly available on GitHub. Since July 2023 it has used a modified Apache License that restricts redistribution of certain paid features, rather than a pure OSI-approved open-source license.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$Can CapRover run across multiple servers?$q$, $q$Yes, CapRover supports Docker Swarm clustering for running apps across more than one node.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$Low-Cost Self-Hosted App Deployment$q$, $q$Indie developers and small startups deploy multiple apps on a single VPS instead of paying per-app managed hosting fees.$q$, $q$Solo developers and small teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$Homelab & Personal Server Hosting$q$, $q$Hobbyists run self-hosted software, such as WordPress, databases, and personal tools, on hardware they own.$q$, $q$Homelab and self-hosting enthusiasts$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited apps on your own server","Automatic SSL via Let's Encrypt","Docker Swarm clustering support","One-click app marketplace","CLI and web dashboard"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$CapRover is a free, self-hosted platform-as-a-service that turns any Docker-enabled server into a one-click app deployment platform. It was created by Kasra Bigdeli, who released the first version, originally called CaptainDuckDuck, in October 2017 to reduce his own hosting costs after relying on Heroku for side projects.$q$, $q$The project has since become widely used among independent developers and small teams: its Docker image has been downloaded more than 150 million times from Docker Hub, and its GitHub repository has attracted over 15,000 stars.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$CapRover automates Docker container orchestration, Nginx reverse-proxy configuration, and Let's Encrypt SSL certificate issuance and renewal, removing most of the manual server administration otherwise needed to run multiple HTTPS-secured apps on one machine.$q$, $q$Deployments can be triggered via the CapRover CLI, a web dashboard, a Git push with an auto-generated webhook, a Dockerfile, or a prebuilt image from Docker Hub or a private registry. Docker Swarm clustering is supported for multi-node setups, and a one-click app marketplace can install common software like WordPress and popular databases without manual server setup.$q$, $q$Licensing has evolved: CapRover began under the Apache License 2.0, but in July 2023 moved to a modified version of that license that restricts redistribution of certain paid or enterprise-oriented features, while the core self-hosted platform remains free to run and its source stays publicly viewable on GitHub.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$There is no CapRover subscription or licensing fee for the core self-hosted platform — it is free to download and run. The only ongoing cost is whatever server infrastructure the user chooses to run it on, which can range from a low-cost VPS to a Raspberry Pi.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4a45bf44-b4ce-425d-98d9-8231b5a94b48', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Contact & Organization Management$q$, $q$Central database of contacts and organizations with custom fields.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Sales Pipelines$q$, $q$Customizable, Kanban-style pipelines for tracking deals through stages.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Task & Project Boards$q$, $q$Post-sale project management boards for tracking delivery work.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$AI Business & Contact Enrichment$q$, $q$Automatically fills in company and contact details, available from the Growth plan up.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$AI Summaries & Meeting Prep$q$, $q$AI-generated record summaries and a beta AI meeting-prep tool.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Email & Calendar Integrations$q$, $q$Native sync with Gmail, Outlook, Microsoft 365, and Google Workspace.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$REST API & Zapier$q$, $q$Custom integrations via a documented REST API or Zapier connections.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Simple enough to set up without a dedicated CRM administrator$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Usable permanent free plan for very small teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Native integrations with common email, accounting, and marketing tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$AI enrichment and summary features included starting at a mid-tier price point$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Free plan is capped at just 2 users and 250 contacts$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Automations, multiple pipelines, and AI features require higher-priced tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Less depth in advanced enterprise features than large enterprise CRMs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Marketing functionality (Transpond) is a separate paid add-on rather than built in$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Is Capsule CRM free?$q$, $q$Yes, Capsule has a free plan for up to 2 users and 250 contacts; paid plans start at $18/user/month billed annually.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Where is Capsule CRM based?$q$, $q$Capsule is built by Zestia Ltd., founded in 2009 and headquartered in Manchester, United Kingdom.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Does Capsule CRM have AI features?$q$, $q$Yes, from the Growth tier up: an AI Pipeline Generator, business and contact enrichment, AI summaries, and a beta AI Meeting Prep tool.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Does Capsule integrate with Gmail and Outlook?$q$, $q$Yes, along with Xero, QuickBooks, Stripe, Mailchimp, Zapier, and a REST API for custom integrations.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Is there a mobile app for Capsule CRM?$q$, $q$Yes, Capsule offers native iOS and Android apps.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Small Business Sales Pipeline Management$q$, $q$Solo founders and small sales teams track deals through a visual pipeline without a complex setup.$q$, $q$Small business owners and sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Agency Client & Project Management$q$, $q$Agencies manage client relationships and post-sale project boards in one system.$q$, $q$Service agencies$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["2 users","250 contacts","1 sales pipeline","5 custom fields"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Starter$q$, $q$$18/user/month$q$, $q$Annual$q$, NULL, $q$["30,000 contacts","Email templates","Shared mailbox","Basic reporting","AI Pipeline Generator"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Growth$q$, $q$$36/user/month$q$, $q$Annual$q$, NULL, $q$["60,000 contacts","Multiple pipelines and project boards","Workflow automations","AI enrichment and summaries"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Advanced$q$, $q$$60/user/month$q$, $q$Annual$q$, NULL, $q$["120,000 contacts","Up to 50 project boards and pipelines"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$Ultimate$q$, $q$$75/user/month$q$, $q$Annual$q$, NULL, $q$["Dedicated account manager","Custom onboarding and training"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Capsule CRM is built by Zestia Ltd., founded in 2009 and headquartered in Manchester, United Kingdom. Capsule has operated for more than 15 years as an independent CRM vendor focused on small and mid-sized businesses, positioning itself as a simpler alternative to larger enterprise CRM platforms.$q$, $q$The core product centers on contact and organization management, customizable Kanban-style sales pipelines, task and activity tracking, and project boards for managing post-sale work.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Capsule integrates natively with Gmail, Outlook, Microsoft 365, and Google Workspace for email and calendar sync, plus Mailchimp, Stripe, Xero, QuickBooks, and Zapier, alongside a REST API for custom integrations.$q$, $q$Starting at the Growth tier, Capsule includes AI features: an AI Pipeline Generator that suggests pipeline structures, AI business and contact enrichment, AI-generated summaries, and an AI Meeting Prep tool currently in beta.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Capsule offers a permanent Free plan for up to 2 users and 250 contacts. Paid plans are billed per user, mostly on an annual basis with a 14-day free trial: Starter at $18/user/month, Growth at $36/user/month, Advanced at $60/user/month, and Ultimate around $75/user/month, each raising contact limits and unlocking more automation, reporting, and AI features.$q$, $q$A separate marketing add-on, Transpond, is available starting around $11/month for lead-capture forms and email marketing campaigns that connect back into the core CRM.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0cb20c33-a4d5-4832-b97f-e2284e29675a', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
