INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$Automatic Captions$q$, $q$Generates on-screen captions in more than 100 languages from raw video.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$AI Dubbing & Lip-Sync$q$, $q$Dubs voiceovers into 30+ languages with synced lip movement.$q$, 1);
