INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$Chat-Based AI Editor$q$, $q$Describe an edit in natural language instead of using a manual timeline.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$Automatic Scene Cutting & B-Roll$q$, $q$AI-assisted scene cuts, B-roll suggestions, transitions, and music placement.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$Credit-Based AI Usage$q$, $q$Monthly AI credit allowances across mobile, desktop, and web apps.$q$, 6);
