INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$Fast localization via AI dubbing into 30+ languages with lip-sync$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$No manual timeline editing required thanks to the chat-based AI editor$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$Available across mobile, desktop, and web$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$Generative AI features require a paid credit-based plan starting at $24.99/month$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$Higher-volume creators can hit credit limits quickly on the entry Max plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$AI avatar and digital-twin content raises likeness and consent considerations creators must manage themselves$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$Training-data exclusion and other enterprise safeguards require a custom-priced plan$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$Is Captions free?$q$, $q$There's a free plan for basic manual editing and captioning. Generative AI features require the Max plan ($24.99/month) or higher.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$What languages does Captions support for dubbing?$q$, $q$AI dubbing supports 30+ languages, while auto-captions are available in 100+ languages.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$What is Mirage Studio?$q$, $q$Mirage Studio, launched in June 2025, is Captions' AI avatar video generation tool, including a personal AI Twin feature.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$Did Captions change its name?$q$, $q$The parent company rebranded to Mirage in September 2025 to reflect its foundation-model strategy, while the consumer app continues operating as Captions.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$How do AI credits work in Captions?$q$, $q$Each paid plan includes a monthly AI credit allotment, and unused credits roll over up to three times the monthly allowance.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$Short-Form Social Video Creation$q$, $q$Individual creators produce talking-head videos with auto captions for platforms like TikTok, Reels, and YouTube Shorts.$q$, $q$Content creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$Multilingual Content Localization$q$, $q$Marketing teams dub existing video into other languages with lip-sync to reach global audiences.$q$, $q$Marketing teams and creators$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Trimming and transitions","Stock media library","Captions in 100+ languages","1 caption template"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$Max$q$, $q$$24.99/month$q$, $q$Monthly (discounted annual option)$q$, NULL, $q$["500 AI credits/month","AI Edit style library","Digital-twin AI actor creation","Chat-based editor","AI B-roll, music, and sound effects"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$Scale 1x$q$, $q$$69.99/month$q$, $q$Monthly$q$, NULL, $q$["1,400 AI credits/month","Everything in Max"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$Scale 2x$q$, $q$$139.99/month$q$, $q$Monthly$q$, NULL, $q$["2,800 AI credits/month","Everything in Max"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$Scale 4x$q$, $q$$279.99/month$q$, $q$Monthly$q$, NULL, $q$["5,600 AI credits/month","Everything in Max"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$Enterprise$q$, $q$Custom$q$, $q$Contact sales$q$, NULL, $q$["Bulk credit discounts","Custom seat options","Dedicated account management","Training-data exclusion"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Captions is an AI video creation app founded in 2021 by Gaurav Misra and Dwight Churchill, former colleagues at Snap Inc., and headquartered in New York City. The company raised funding from Sequoia Capital, Andreessen Horowitz, and Index Ventures, reaching a roughly $500 million valuation in a 2024 Series C round.$q$, $q$In September 2025, the parent company renamed itself Mirage to reflect a strategic focus on building its own proprietary video-generation foundation model, while the consumer-facing app continues to operate under the Captions name.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Captions started as an automatic captioning tool, generating on-screen captions in more than 100 languages, and expanded into a fuller AI video toolkit with automatic scene cutting, B-roll suggestions, and AI dubbing with lip-sync into more than 30 languages, letting a single video be localized for multiple markets.$q$, $q$Mirage Studio, launched in June 2025, generates AI avatar videos, including a personal AI Twin digital likeness of the creator, from a text prompt or audio track. A chat-based AI editor lets users describe an edit in natural language instead of manipulating a manual timeline.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('847ca3ae-c901-4b57-8fe3-f9b3380035c8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Captions uses a freemium, credit-based pricing model. The Free plan covers basic manual editing and captioning without AI credits. The Max plan, at $24.99/month, includes 500 monthly AI credits and unlocks the full AI production toolkit, digital-twin creation, and the chat-based editor.$q$, $q$Three Scale tiers scale up the monthly credit allowance for higher-volume creators and teams: Scale 1x ($69.99/month, 1,400 credits), Scale 2x ($139.99/month, 2,800 credits), and Scale 4x ($279.99/month, 5,600 credits). An Enterprise plan offers custom pricing with bulk credit discounts, dedicated account management, and training-data exclusion.$q$]::text[], 2);
