-- Enrichment marathon batch: Canny, Canva, Canvas LMS, Capacities, Capchase, CapRover, Capsule CRM, Captions

-- ── Canny ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Canny is a customer feedback and product roadmap platform that helps SaaS teams collect feature requests, prioritize them with AI, and publish public changelogs.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $79/month)$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Canny: Customer Feedback & Roadmap Software$q$, seo_title),
  seo_meta_description = COALESCE($q$Canny helps product teams collect feedback, prioritize features with AI Autopilot, and share public roadmaps and changelogs. Free plan available.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Canny is a customer feedback and product management platform used by software companies to collect feature requests, prioritize them, and communicate what they are building. Founded in 2015 by Sarah Hum and Andrew Rasmussen, former Meta employees, Canny is headquartered in San Francisco and has operated as a bootstrapped, profitable business rather than a venture-funded startup. The core workflow centers on three connected surfaces: feedback boards where users and internal teams submit and upvote ideas, one or more roadmaps that show what is planned, in progress, and shipped, and a changelog that announces completed work back to the people who requested it. Canny's AI feature, called Autopilot, is included on every plan including the free tier; it automatically groups duplicate or related feedback posts, summarizes long comment threads, drafts replies, and surfaces themes across large volumes of submissions so product teams do not have to manually triage every entry. Feedback can be captured directly inside Canny's own hosted boards or pulled in from third-party channels such as Intercom, Zendesk, Slack, and a Chrome extension, letting support and sales teams log a customer request without leaving their existing tools. On the delivery side, Canny integrates with issue trackers and project management tools including Jira, Linear, ClickUp, Asana, GitHub, and Azure DevOps, so prioritized items can be pushed to an engineering backlog without manual re-entry. Pricing follows a freemium, tracked-user-based model. The Free plan supports up to 25 tracked users and five manager seats with unlimited posts and boards. The Pro plan, priced at $79 per month when billed yearly (roughly 20 percent cheaper than monthly billing), raises the tracked-user ceiling and adds custom domains, content translation, project management integrations, user segmentation, automation rules, and custom admin roles, and is described by Canny as its most popular tier. The Business plan is a custom-quoted tier for larger organizations that adds single sign-on, CRM integrations, and enterprise-scale support, and requires contacting Canny's sales team for pricing. Canny also offers reduced-rate plans for qualified non-profits and high-volume consumer products. The product is aimed at product managers, founders, and customer success teams at SaaS companies who need a single, public or private system of record for what customers are asking for, rather than tracking requests in spreadsheets or support tickets. Typical users include B2B software vendors publishing a public roadmap to build trust with customers, and internal product teams using Canny privately to prioritize a backlog. Because Canny is bootstrapped and has been operating profitably for close to a decade, it is often cited in the SaaS community as an example of a durable, founder-led feedback tool. Canny's own feedback portal is itself an example of the product, since the company uses Canny internally to manage its own roadmap and changelog.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'de66f380-8299-4b3a-b413-b14569d70119';

