-- ── Canva ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Canva is a web-based design platform offering drag-and-drop tools, AI-powered Magic Studio features, and hundreds of thousands of templates for social media, presentations, and print.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Pro from $15/month)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$4,000+ employees$q$, company_size),
  headquarters = COALESCE($q$Sydney, Australia$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$, $q$French$q$, $q$German$q$, $q$Portuguese$q$, $q$Italian$q$, $q$Dutch$q$, $q$Japanese$q$, $q$Korean$q$, $q$Chinese (Simplified)$q$]::text[],
  seo_title = COALESCE($q$Canva: AI Design Platform, Pricing & Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Canva is a free-to-start design platform with AI Magic Studio tools, templates, and team plans. See Canva's pricing, key features, and plan comparison.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Canva is a web-based graphic design and visual content platform founded in Perth, Australia, and officially launched in August 2013 by Melanie Perkins, Cliff Obrecht, and Cameron Adams. Perkins conceived the idea while teaching university students to use complex desktop design software and wanted a simpler, browser-based alternative; after being turned down by more than 100 investors, she and Obrecht eventually built the company into one of the most highly valued private software companies in the world, headquartered in Sydney, Australia, with additional offices including Manila, and a workforce that has grown past 4,000 employees. Canva's core product is a drag-and-drop design editor that runs in the browser and as native apps for iOS, Android, Mac, and Windows, giving non-designers a way to produce social media graphics, presentations, documents, videos, websites, and printed marketing materials from a single library of templates. The Free plan includes access to more than 250,000 templates, 5GB of cloud storage, and Canva's basic editing, template, and stock-asset library at no cost, which is a major reason Canva has scaled to tens of millions of monthly active users across consumer, education, and business segments. Paid tiers unlock more capability rather than gating the core editor. Canva Pro costs $15 per month or $120 per year for a single user and adds premium templates and stock content, 1TB of storage, unlimited Brand Kits, a background remover, and Canva's Magic Studio suite of generative AI tools — including Magic Write for text generation, Magic Design for automated layout suggestions, Magic Eraser, Magic Expand, and AI-assisted video and image editing. The Business plan (formerly sold as Canva for Teams) costs $20 per user per month or $200 per user per year and adds shared brand controls, approval workflows, and team-wide asset libraries for small and mid-sized organizations; Canva has been migrating existing customers off the older flat-rate Teams plan toward this per-seat Business pricing. An Enterprise plan is available for large organizations that need single sign-on, SCIM user provisioning, audit logs, and a dedicated customer success manager, priced on a custom quote and generally requiring a minimum of roughly 150 seats. Canva also sells a separate AI Pass add-on for Pro and Business subscribers, priced around $100 per person per month, that substantially raises the usage limits on its AI features beyond what is bundled into the base subscription. Beyond the design editor, Canva has expanded into an adjacent productivity suite: Canva Docs for word processing, Canva Whiteboards for visual collaboration, Canva Presentations, and Canva Sheets, alongside a print-and-merchandise fulfillment service and a developer platform (Canva Apps SDK and Canva Connect API) that powers an apps marketplace with more than 300 third-party integrations for tools like Slack, HubSpot, Dropbox, and Asana. Canva for Education and Canva for Nonprofits provide the Pro feature set for free to verified teachers, students, and registered nonprofits. Typical users range from individual creators and small business owners who need professional-looking graphics without design training, to marketing teams at larger companies that use Canva's Brand Kit and approval workflows to keep visual output on-brand across many contributors. Because of its low barrier to entry, broad template library, and integrated AI tools, Canva is commonly positioned as an alternative to a combination of Adobe Creative Cloud, PowerPoint, and stock-photo subscriptions for teams that do not need professional-grade pixel-level design control.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7e8227b7-0e90-46d7-92df-86b14a774f8a';

