-- ── Canvas LMS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Canvas LMS is Instructure's cloud-based learning management system for K-12 and higher-ed institutions, also available as free, self-hosted open-source software.$q$, short_description),
  pricing_model = COALESCE($q$Institutional / custom (also free as self-hosted open source)$q$, pricing_model),
  starting_price = COALESCE($q$Free (open-source, self-hosted)$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE($q$~2,200 employees$q$, company_size),
  headquarters = COALESCE($q$Salt Lake City, Utah, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$, $q$French$q$, $q$German$q$, $q$Portuguese$q$, $q$Chinese$q$, $q$Japanese$q$]::text[],
  seo_title = COALESCE($q$Canvas LMS: Features, Pricing & Open Source Option$q$, seo_title),
  seo_meta_description = COALESCE($q$Canvas LMS by Instructure is a cloud learning management system used by 4,000+ schools, with a free, self-hosted open-source version also available.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Canvas is a learning management system (LMS) created by Instructure, a Salt Lake City, Utah-based education technology company founded in 2008 by Brigham Young University graduate students Brian Whitmer and Devlin Daley. Instructure built Canvas as a cloud-native alternative to older, on-premise LMS platforms such as Blackboard, and launched the product in 2011. Canvas is now used by more than 4,000 educational institutions and roughly 28 million students, teachers, and administrators worldwide, spanning K-12 schools, universities, and corporate or professional training programs. A distinguishing feature of Canvas is that it is dual-licensed: Instructure sells and hosts a commercial version of Canvas to institutions under custom, negotiated contracts, while the underlying codebase is also released as free, open-source software under the AGPLv3 license on GitHub, allowing any organization with the technical resources to self-host and run Canvas at no licensing cost. Institutional pricing for the hosted commercial version is not published; third-party estimates commonly cite a per-student annual range, though actual contract terms vary widely by institution size and negotiated terms, and prospective customers must contact Instructure's sales team for a quote. Core Canvas features include a course and content management system where instructors build modules, assignments, quizzes, and discussion boards; a Gradebook that supports customizable grading schemes and weighted categories; and SpeedGrader, a tool that lets instructors view a student's submission, rubric, and grade entry on one screen, annotate PDFs directly, and leave text or video feedback. Canvas also includes Mastery Paths and integration with Instructure's Mastery Connect and Outcomes tools, which let instructors build competency-based learning sequences that branch based on how a student performs on a given assessment. Beyond the core LMS, Instructure offers companion products under the same Canvas umbrella, including Canvas Studio for video-based learning and Canvas Commons for sharing course content between instructors and institutions. Canvas has one of the most extensively documented APIs in the LMS category, with several hundred REST endpoints, and it supports the LTI (Learning Tools Interoperability) standard, which lets institutions connect Canvas to more than 1,000 third-party educational tools, from publisher content to proctoring and plagiarism-detection services. Native mobile apps are available for both students and instructors on iOS and Android, covering assignment submission, discussion participation, grade checking, and mobile SpeedGrader for on-the-go feedback. Instructure previously offered a free hosted account for individual teachers outside of an institutional contract, but took that specific offering offline following a security incident in 2026; the self-hosted open-source version remains available at no cost to anyone willing to run and maintain their own servers. Canvas is best suited for accredited schools, universities, and training organizations that need a scalable, API-extensible LMS with a large third-party integration ecosystem, as opposed to individual educators or very small training providers looking for an out-of-the-box, no-setup tool.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2db842ea-f8cf-4398-9294-2de09ec16c62';

