-- ── Capacities ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Capacities is an object-based note-taking and personal knowledge management app that organizes information as linked objects instead of files and folders.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Pro from $9.99/month billed annually)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Sankt Wendel, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$Capacities: Object-Based Note-Taking App & Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Capacities is a note-taking app that organizes ideas as connected objects. See its features, AI assistant, and Free, Pro, and Believer pricing plans.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Capacities is a personal knowledge management and note-taking application built by Capacities Labs GmbH, a German company founded in 2020 by Steffen Bleher and Michael von Hohnhorst and based in Sankt Wendel, Germany. The product differentiates itself from conventional note apps such as Notion or Obsidian by organizing information around typed objects rather than freeform pages or files. Instead of creating a generic document, a Capacities user creates an object of a defined type — for example a Person, a Book, a Meeting, or a Daily Note — and each object type can carry its own structured properties, such as dates, ratings, or links to other objects, in addition to free-form text content. Objects can be linked to one another, and Capacities renders those links as an interactive graph view, letting users navigate their knowledge base by relationship rather than folder hierarchy. Core features include Daily Notes for quick capture, custom object types and templates, properties and relations for structuring data, tagging and collections for grouping related objects, and an AI assistant, available on paid plans, that can answer questions about a user's own notes, summarize content, and help draft new entries. The app is offline-first: content is stored locally and synced across devices once a connection is available, and users can export their entire knowledge base to Markdown, HTML, or JSON, which the company positions as a way to avoid vendor lock-in. Capacities is available as native desktop apps for Mac, Windows, and Linux, as a web app usable in any browser, and, since mobile apps launched in July 2024, as native iOS and Android apps, with tablet-optimized versions for iPad and Android tablets added shortly after. Pricing follows a freemium model. The Free plan has no cap on the number of notes or objects a user can create and includes 5GB of storage for embedded media, making it usable as a primary note-taking tool without paying. The Pro plan costs $9.99 per month when billed annually, or $11.99 billed monthly, and removes the storage cap while adding access to the AI assistant, saved queries, calendar integration, and priority support. A Believer plan, priced at $12.49 per month annually or $14.99 monthly, includes the same feature set as Pro but is positioned by the company as a way for users to directly support ongoing development of the product. Capacities is aimed at people who think in terms of interconnected concepts rather than linear documents — researchers, writers, and knowledge workers building a structured personal knowledge base — and it competes most directly with Notion, Obsidian, Roam Research, and Tana in the personal knowledge management category.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5816d708-5e16-4d8f-8847-bc4d396ab602';

