-- ── Capchase ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Capchase is a fintech platform that gives B2B SaaS companies non-dilutive financing by advancing future subscription revenue and flexible payment options for buyers.$q$, short_description),
  pricing_model = COALESCE($q$Usage/deal-based financing fee (not a subscription)$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing (deal-based)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$New York, USA (with offices in Madrid and Barcelona)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$]::text[],
  seo_title = COALESCE($q$Capchase: Revenue Financing & B2B Payments for SaaS$q$, seo_title),
  seo_meta_description = COALESCE($q$Capchase offers non-dilutive revenue financing (Capchase Grow) and flexible B2B payment options (Capchase Pay) for software companies.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Capchase is a financial technology company that provides revenue-based financing and B2B payment infrastructure for software companies. Founded in 2020, Capchase is headquartered in New York with additional offices in Madrid and Barcelona, and has funded more than 4,000 companies with over $2.5 billion in total financing according to the company's own published figures. The company's flagship product, Capchase Grow, is a non-dilutive financing tool that lets SaaS companies borrow against their own future annual recurring revenue (ARR) instead of raising equity or taking on traditional venture debt. Rather than requiring a pitch deck or business plan, Capchase asks applicants to connect their banking, accounting, and billing systems through secure data integrations; its underwriting algorithms then assess the quality and durability of a company's recurring contracts and typically return a financing offer within 24 to 48 hours. Through Capchase Grow, eligible companies can access an advance of roughly 20 to 70 percent of their ARR, with individual transaction sizes ranging from about $25,000 to $10 million and repayment terms generally spanning three to twelve months, though some financing arrangements extend longer. Pricing on Grow is structured as a flat discount fee, commonly cited in the 10 to 12 percent range over the term of the advance, split since 2023 into a separate Platform Fee, roughly 1 to 4 percent depending on financing terms, which covers access to the Capchase Grow platform, and a Financing Fee that covers the cost of capital itself; companies generally need a minimum ARR floor, commonly cited around $150,000, and a minimum cash runway to qualify. Capchase's second core product, Capchase Pay, is a B2B buy-now-pay-later style tool aimed at the sales side of the transaction: it lets a software vendor's customers pay for an annual or multi-year contract in installments while the vendor still receives the full contract value upfront. Vendor customers can be qualified in about a minute using automated data checks, and the flat financing fee on a Capchase Pay transaction can be paid by the vendor, the buyer, or split between the two, with no separate platform, implementation, or integration fees and setup times commonly cited as under 24 hours. Because pricing on both products is negotiated per company and per deal based on underwriting output, Capchase does not publish a fixed-rate pricing page in the way a typical SaaS subscription product would; prospective customers apply through the website and receive individualized terms. Capchase is aimed primarily at venture-backed and growth-stage B2B SaaS and hardware companies that want to smooth out cash flow from annual contracts, extend runway between funding rounds, or offer flexible payment terms to their own customers without absorbing the credit risk themselves, positioning it against alternatives such as traditional venture debt, other revenue-based financing providers, and in-house installment billing built directly into a company's own billing stack.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '53147b31-f2fc-40d8-abf5-b79accdf962a';

