-- ── CapRover ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CapRover is a free, self-hosted platform-as-a-service that turns any Docker-enabled server into a one-click app deployment platform with automatic SSL.$q$, short_description),
  pricing_model = COALESCE($q$Free (self-hosted, source-available)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CapRover: Free Self-Hosted PaaS for Docker Apps$q$, seo_title),
  seo_meta_description = COALESCE($q$CapRover is a free, self-hosted PaaS that automates Docker and Nginx to deploy apps, databases, and free SSL certificates on your own server.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CapRover is a free, self-hosted platform-as-a-service (PaaS) that lets developers turn any Docker-enabled server, from a cloud VM on AWS, DigitalOcean, or Hetzner to a Raspberry Pi, into a one-click application deployment platform similar to Heroku. The project was created by Kasra Bigdeli, an engineering leader, who built the first version, originally named CaptainDuckDuck, in October 2017 to reduce his own hosting costs after relying on Heroku for side projects; the project was later renamed CapRover. It has since become one of the more widely used self-hosted PaaS tools among independent developers and small teams, with its official Docker image downloaded more than 150 million times from Docker Hub and its GitHub repository (caprover/caprover) attracting over 15,000 stars. Under the hood, CapRover automates Docker container orchestration, Nginx reverse-proxy configuration, and Let's Encrypt SSL certificate issuance and renewal, removing most of the manual server administration that would otherwise be required to run multiple web applications behind HTTPS on a single machine. Deployments can be triggered from the CapRover CLI, a web-based dashboard, a Git push with an auto-generated webhook, a Dockerfile, or a prebuilt image pulled from Docker Hub or a private registry. CapRover also supports Docker Swarm clustering for teams that need to run apps across more than one node, and it ships with a library of one-click apps that can install common software such as WordPress, MySQL, MariaDB, MongoDB, PostgreSQL, and other popular open-source tools with a single click rather than a manual server setup. Because there is no vendor-hosted service or subscription involved, CapRover has no recurring product fee: the only ongoing cost is whatever server the user chooses to run it on. One nuance worth noting is licensing: CapRover was originally released under the Apache License 2.0, but in July 2023 the project moved to a modified version of that license that places some redistribution restrictions on certain paid or enterprise-oriented features, while the core deployment platform used by most self-hosters remains free to run and its source remains publicly viewable on GitHub. CapRover is best suited for individual developers, small startups, and hobbyists who want Heroku-style deployment convenience without paying Heroku-style hosting fees, and who are comfortable managing their own server instead of using a fully managed cloud platform. It is commonly compared to other self-hosted deployment tools such as Coolify, Dokploy, and Portainer, and to managed alternatives like Render, Railway, and Northflank for teams that would rather not administer their own server at all.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4a45bf44-b4ce-425d-98d9-8231b5a94b48';

