-- ── Capsule CRM ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Capsule CRM is a UK-based customer relationship management platform for small and mid-sized businesses, with sales pipelines, project boards, and AI tools.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $18/user/month billed annually)$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Manchester, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Capsule CRM: Pricing, Features & Free Plan$q$, seo_title),
  seo_meta_description = COALESCE($q$Capsule CRM is a UK-built CRM for small and mid-sized businesses with sales pipelines, AI enrichment, and a free plan for up to 2 users.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Capsule CRM is a customer relationship management platform built by Zestia Ltd., a company founded in 2009 and headquartered in Manchester, United Kingdom. Capsule has operated for more than 15 years as an independent CRM vendor focused primarily on small and mid-sized businesses rather than large enterprises, positioning itself as a simpler, less configuration-heavy alternative to CRM platforms such as Salesforce or HubSpot. The core product centers on contact and organization management, customizable sales pipelines displayed as Kanban-style boards, task and activity tracking, and project boards for managing work after a deal closes. Capsule integrates natively with common productivity and finance tools, including Gmail, Outlook, Microsoft 365, and Google Workspace for email and calendar sync, Mailchimp for email marketing, Stripe, Xero, and QuickBooks for billing and accounting, and Zapier along with a REST API for custom integrations. Starting at its Growth tier, Capsule has added a set of AI features, including an AI Pipeline Generator that suggests pipeline structures, AI business and contact enrichment that fills in company and contact details automatically, AI-generated summaries of records and activity, and an AI Meeting Prep tool, in beta, that compiles relevant context ahead of a scheduled meeting. Capsule's pricing is tiered by user count and feature access, billed primarily on an annual basis with a 14-day free trial on paid plans. A permanent Free plan supports up to 2 users, 250 contacts, 5 custom fields, and a single sales pipeline, which is enough for a very small team or a solo operator to run basic contact management at no cost. The Starter plan, priced at $18 per user per month on annual billing, raises the contact limit to 30,000, and adds email templates, a shared team mailbox, basic reporting, premium integrations such as Xero and Zendesk, and the AI Pipeline Generator. The Growth plan, at $36 per user per month annually, doubles the contact limit to 60,000 and adds multiple sales pipelines, project boards, workflow automations, advanced sales reporting and dashboards, and the AI enrichment and summary features. The Advanced plan, at $60 per user per month annually, raises the contact ceiling further to 120,000 and increases the number of project boards and pipelines a team can run. The Ultimate plan sits at the top of the range, generally cited around $75 per user per month on annual billing, and adds a dedicated account manager and custom onboarding and training for larger SMB teams that want enterprise-style support without moving to a full enterprise CRM. Capsule also sells an add-on marketing product, Transpond, starting around $11 per month, for lead-capture forms and email marketing campaigns that connect back into the core CRM. Capsule is best suited for small businesses, agencies, and sales teams that want a CRM they can set up and use within a day, rather than a highly configurable enterprise platform that typically requires a dedicated administrator or implementation partner.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0cb20c33-a4d5-4832-b97f-e2284e29675a';

