-- ── Captions ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Captions is an AI video creation app that generates automatic captions, AI dubbing, and AI avatar videos, letting creators produce studio-style videos from raw footage.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $24.99/month)$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$New York City, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Captions: AI Video Editor, Captions & Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Captions is an AI video app for auto captions, AI dubbing in 30+ languages, and AI avatar videos. Compare Free, Max, and Scale pricing plans.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Captions is an AI-powered video creation app founded in 2021 by Gaurav Misra and Dwight Churchill, who previously worked together at Snap Inc. before starting the company. Headquartered in New York City, Captions raised funding from investors including Sequoia Capital, Andreessen Horowitz, and Index Ventures, and in a 2024 Series C round was valued at roughly $500 million. In September 2025, the parent company renamed itself Mirage to reflect a broader strategic focus on building its own proprietary video-generation foundation model and future video products, while the original Captions app and its feature set continue to operate under the Captions name for end users. The product's original core use case is automatic captioning: users upload raw video and Captions generates on-screen captions in more than 100 languages, along with a library of animated caption styles. From there, the app expanded into a fuller AI video production toolkit that includes automatic scene cutting, B-roll suggestions, transition and music placement, and AI-driven audio dubbing into more than 30 languages with lip-sync, allowing a single piece of footage to be localized for multiple markets without re-shooting. More recent additions include Mirage Studio, launched in June 2025, which generates AI avatar-based videos, including a personal AI Twin digital likeness of the creator, from a text prompt or an audio track, and a chat-based AI editor that lets users describe an edit in natural language rather than manipulating a manual timeline. Captions is available as native apps for iOS, Android, desktop, and web. Pricing follows a freemium, credit-based model. The Free plan includes basic manual editing tools such as trimming and transitions, access to the stock media library, and captioning, but does not include generative AI credits. The Max plan, at $24.99 per month with a discounted annual option, is the entry-level paid tier and includes 500 AI credits per month along with access to the AI Edit style library, full AI-assisted video production, digital-twin custom AI actor creation, the chat-based editor, and AI-generated B-roll, music, and sound effects. Above Max, three Scale tiers, Scale 1x at $69.99 per month with 1,400 credits, Scale 2x at $139.99 per month with 2,800 credits, and Scale 4x at $279.99 per month with 5,600 credits, offer proportionally larger monthly AI credit allowances and access to enhanced AI model options for creators and teams producing higher volumes of video. Unused credits roll over month to month up to three times the monthly allowance. An Enterprise plan is available on custom pricing for organizations that need bulk credit discounts, custom seat counts, dedicated account management, and a guarantee that their content will not be used to train Captions' models. The product is aimed primarily at individual content creators, social media marketers, and small video teams who want to produce short-form talking-head or narrated video content quickly, without traditional timeline-based video editing skills or a professional production setup.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '847ca3ae-c901-4b57-8fe3-f9b3380035c8';

